mapper.select:
SELECT txn_id, gmt_create, gmt_modified, gmt_complete, payer_account_id, payee_account_id, amount, currency, type, status, failure_reason, ext_info, category FROM transaction WHERE payer_account_id = #{accountId} AND status IN
#{s}
LIMIT 1

SELECT
txn_id, gmt_create, gmt_modified, gmt_complete,
payer_account_id, payee_account_id, amount, currency,
type, status, failure_reason, ext_info, category
FROM transaction

    AND (payer_account_id = #{accountId} OR payee_account_id = #{accountId})


        AND payer_account_id = #{payerAccountId}



        AND gmt_create >= #{gmtCreate}



        AND gmt_complete <= #{gmtComplete}



        AND amount >= #{amountMin}


        AND amount <= #{amountMax}



        AND category = #{txnCategory}



        AND type = #{txnType}



        AND status = #{txnStatus}


ORDER BY gmt_create DESC
LIMIT #{pageSize} OFFSET #{pageNo}

mapper.update:
UPDATE transaction
status = #{status}, failure_reason = #{failureReason}, ext_info = #{extInfo}, gmt_complete = #{gmtComplete}, gmt_modified = NOW()
WHERE txn_id = #{txnId}

mapper.select:
SELECT COUNT(*)
FROM transaction
WHERE payer_account_id = #{accountId}

SELECT
txn_id, gmt_create, gmt_modified, gmt_complete,
payer_account_id, payee_account_id, amount, currency,
type, status, failure_reason, ext_info, category
FROM transaction

    AND payee_account_id = #{accountId}


        AND gmt_create >= #{gmtCreate}



        AND amount >= #{amountMin}


        AND amount <= #{amountMax}



        AND category = #{txnCategory}



        AND type = #{txnType}



        AND status = #{txnStatus}


ORDER BY gmt_create DESC
LIMIT #{pageSize} OFFSET #{pageNo}

SELECT COALESCE(SUM(amount), 0)
FROM transaction
WHERE payee_account_id = #{merchantId}
AND status = 'FINISH'

    AND gmt_complete >= #{gmtCreateFrom}


    AND gmt_complete <= #{gmtCreateTo}

SELECT COALESCE(AVG(amount), 0)
FROM transaction
WHERE payee_account_id = #{merchantId}
AND status = 'FINISH'
AND gmt_complete >= #{gmtCreateFrom}
AND gmt_complete <= #{gmtCreateTo}

SELECT COUNT(DISTINCT payer_account_id)
FROM transaction
WHERE payee_account_id = #{merchantId}
AND status = 'FINISH'
AND gmt_complete >= #{gmtCreateFrom}
AND gmt_complete <= #{gmtCreateTo}
AND payer_account_id NOT IN (
    SELECT DISTINCT payer_account_id
    FROM transaction
    WHERE payee_account_id = #{merchantId}
    AND status = 'FINISH'
    AND gmt_complete < #{gmtCreateFrom}
)
